import json
import re
import os
import math

# Find the temporary JSON files for clinical and mutation data
base_path = '/tmp'
files_in_tmp = os.listdir(base_path) if os.path.exists(base_path) else []

clinical_file = None
cdh1_file = None

print("Looking for files in /tmp...")
for f in files_in_tmp:
    print(f"Found: {f}")
    if 'clinical' in f.lower() or re.search(r'tmp[a-z0-9]+\.json$', f):
        if not clinical_file:  # Take the first one if not set
            clinical_file = os.path.join(base_path, f)
    if 'mutation' in f.lower() or 'cdh1' in f.lower() or re.search(r'tmp[a-z0-9]+\.json$', f):
        if not cdh1_file or 'mutation' in f.lower() or 'cdh1' in f.lower():
            cdh1_file = os.path.join(base_path, f)

print(f"\nClinical file: {clinical_file}")
print(f"CDH1 mutation file: {cdh1_file}")

# Check if files exist
if clinical_file and os.path.exists(clinical_file):
    try:
        with open(clinical_file, 'r') as f:
            female_bladder_clinical = json.load(f)
        print(f"\nLoaded {len(female_bladder_clinical)} female bladder cancer clinical records")
    except:
        print("Error loading clinical file")
        female_bladder_clinical = []
else:
    print("Clinical file not found")
    female_bladder_clinical = []

if cdh1_file and os.path.exists(cdh1_file) and cdh1_file != clinical_file:
    try:
        with open(cdh1_file, 'r') as f:
            cdh1_mutations = json.load(f)
        print(f"Loaded {len(cdh1_mutations)} CDH1 mutation records")
    except:
        print("Error loading mutation file")
        cdh1_mutations = []
else:
    print("CDH1 mutation file not found or same as clinical file")
    # Try to find another file that might be the mutation data
    for f in files_in_tmp:
        if f.endswith('.json') and os.path.join(base_path, f) != clinical_file:
            with open(os.path.join(base_path, f), 'r') as fobj:
                test_data = json.load(fobj)
                if len(test_data) > 0 and 'ParticipantBarcode' in str(test_data[0]):
                    cdh1_mutations = test_data
                    print(f"Found mutation data in {f}: {len(cdh1_mutations)} records")
                    break
    else:
        cdh1_mutations = []

print("__RESULT__:")
print(json.dumps({
    "clinical_loaded": len(female_bladder_clinical) if 'female_bladder_clinical' in locals() else 0,
    "mutations_loaded": len(cdh1_mutations) if 'cdh1_mutations' in locals() else 0
}))

