import json
import re
import os
import math

# Find the temporary JSON files for clinical and mutation data
base_path = '/tmp'
files_in_tmp = os.listdir(base_path) if os.path.exists(base_path) else []

clinical_file = None
cdh1_file = None

print("Looking for files in /tmp...")
for f in files_in_tmp:
    print("Found: " + f)
    if 'clinical' in f.lower() or (re.search(r'tmp[a-z0-9]+\.json$', f) and not clinical_file):
        clinical_file = os.path.join(base_path, f)
    if 'mutation' in f.lower() or 'cdh1' in f.lower():
        cdh1_file = os.path.join(base_path, f)

print("\nClinical file: " + str(clinical_file))
print("CDH1 mutation file: " + str(cdh1_file))

# Check if files exist and load them
female_bladder_clinical = []
cdh1_mutations = []

if clinical_file and os.path.exists(clinical_file):
    try:
        with open(clinical_file, 'r') as f:
            female_bladder_clinical = json.load(f)
        print("\nLoaded {} female bladder cancer clinical records".format(len(female_bladder_clinical)))
    except:
        print("Error loading clinical file")

# If no specific mutation file found, try other files
if not cdh1_file or not os.path.exists(cdh1_file):
    for f in files_in_tmp:
        if f.endswith('.json') and os.path.join(base_path, f) != clinical_file:
            try:
                with open(os.path.join(base_path, f), 'r') as fobj:
                    test_data = json.load(fobj)
                    if len(test_data) > 0 and 'ParticipantBarcode' in str(test_data[0]):
                        cdh1_mutations = test_data
                        print("Found mutation data in {}: {} records".format(f, len(cdh1_mutations)))
                        break
            except:
                continue
else:
    try:
        with open(cdh1_file, 'r') as f:
            cdh1_mutations = json.load(f)
        print("Loaded {} CDH1 mutation records".format(len(cdh1_mutations)))
    except:
        print("Error loading mutation file")

# Process the data if we have both
if female_bladder_clinical and cdh1_mutations:
    # Extract participant barcodes and histological types
    patient_histology = {}
    for record in female_bladder_clinical:
        desc = record.get('Patient_description', '')
        hist_type = record.get('histological_type', '')

        match = re.search(r'(TCGA-\w{2}-\w{4})', desc)
        if match and hist_type and hist_type not in ['None', '[Not Applicable]', '']:
            barcode = match.group(1)
            patient_histology[barcode] = hist_type.strip()

    # Get set of patients with CDH1 mutations
    cdh1_patients = set([rec['ParticipantBarcode'] for rec in cdh1_mutations])

    # Build the contingency table
    contingency_table = {}
    for barcode, hist_type in patient_histology.items():
        if hist_type not in contingency_table:
            contingency_table[hist_type] = [0, 0]  # [mutated, not mutated]

        if barcode in cdh1_patients:
            contingency_table[hist_type][0] += 1
        else:
            contingency_table[hist_type][1] += 1

    # Filter out categories with marginal totals <= 10
    filtered_table = {}
    for hist_type, counts in contingency_table.items():
        total = counts[0] + counts[1]
        if total > 10:
            filtered_table[hist_type] = counts
        else:
            print("Excluding {}: total = {}".format(hist_type, total))

    print("Filtered contingency table has {} categories".format(len(filtered_table)))

    result = {
        "clinical_patients": len(patient_histology),
        "cdh1_all_patients": len(cdh1_patients),
        "filtered_table_size": len(filtered_table),
        "table": filtered_table
    }
else:
    result = {
        "clinical_patients": len(female_bladder_clinical),
        "mutations_loaded": len(cdh1_mutations),
        "error": "Missing required data"
    }

print("__RESULT__:")
print(json.dumps(result))

