import json
import re
import os
import glob

# Find and load all available JSON files from queries
base_path = '/tmp'
all_files = glob.glob(os.path.join(base_path, 'tmp*.json'))

print("Found {} temporary files".format(len(all_files)))
female_bladder_clinical = []
cdh1_mutations = []

# Load all files and determine what they contain
for file_path in all_files:
    try:
        with open(file_path, 'r') as f:
            data = json.load(f)

        if len(data) > 0:
            # Check what this file contains
            first_item = data[0]

            # If it has Patient_description and histological_type, it's clinical data
            if 'Patient_description' in first_item and 'histological_type' in first_item:
                female_bladder_clinical.extend(data)
                print("Loaded clinical data from {}: {} records".format(os.path.basename(file_path), len(data)))

            # If it has ParticipantBarcode and Hugo_Symbol, it's mutation data
            elif 'ParticipantBarcode' in first_item and ('Hugo_Symbol' in first_item or 'FILTER' in first_item):
                # Filter for CDH1 mutations only
                cdh1_records = [rec for rec in data if rec.get('Hugo_Symbol') == 'CDH1']
                if cdh1_records:
                    cdh1_mutations.extend(cdh1_records)
                    print("Loaded CDH1 mutation data from {}: {} records".format(os.path.basename(file_path), len(cdh1_records)))
            elif 'ParticipantBarcode' in first_item:
                # Might be a list of barcodes with CDH1 mutations
                cdh1_mutations.extend(data)
                print("Loaded potential mutation data from {}: {} records".format(os.path.basename(file_path), len(data)))

    except Exception as e:
        continue

print("\nTotal clinical records: {}".format(len(female_bladder_clinical)))
print("Total CDH1 mutation records: {}".format(len(cdh1_mutations)))

# Process clinical data to extract patient barcodes and histological types
if female_bladder_clinical:
    patient_histology = {}
    for record in female_bladder_clinical:
        desc = record.get('Patient_description', '')
        hist_type = record.get('histological_type', '')

        match = re.search(r'(TCGA-\w{2}-\w{4})', desc)
        if match and hist_type and hist_type not in ['None', '[Not Applicable]', '']:
            barcode = match.group(1)
            patient_histology[barcode] = hist_type.strip()

    print("Processed {} patients with valid histological types".format(len(patient_histology)))

    # Get unique CDH1 mutation patients
    if cdh1_mutations:
        cdh1_patients = set()
        for rec in cdh1_mutations:
            if isinstance(rec, dict) and 'ParticipantBarcode' in rec:
                cdh1_patients.add(rec['ParticipantBarcode'])
        print("Found {} unique patients with CDH1 mutations".format(len(cdh1_patients)))

        # Check overlap
        bladder_patients = set(patient_histology.keys())
        overlap = bladder_patients.intersection(cdh1_patients)
        print("Overlap (bladder patients with CDH1 mutations): {}".format(len(overlap)))

        result = {
            "clinical_patients": len(patient_histology),
            "cdh1_all_patients": len(cdh1_patients),
            "overlap": len(overlap)
        }
    else:
        result = {"clinical_patients": len(patient_histology), "error": "No CDH1 mutations data"}
else:
    result = {"error": "No clinical data loaded"}

print("__RESULT__:")
print(json.dumps(result))

